INSERT INTO "Character" (id, name, category, description, "promptConsistency", "updatedAt") VALUES (gen_random_uuid(), 'Si Piko', 'Animal', 'An orange chubby tabby cat that loves eating snacks.', 'A fat orange tabby cat mascot character named Si Piko, plump round chubby body, large round head with full puffed cheeks, big expressive amber gold eyes with soft radial gradient and two catchlights, small pink triangular nose, soft closed mouth smile, short stubby legs, thick tail with alternating orange and brown tabby rings curled to one side, cream colored belly muzzle chin and paw fur, small triangular ears with pale pink inner fur, six long white whiskers, wearing a small red woven collar with a round gold bell, sitting beside a ceramic snack bowl, clean cel shaded cartoon mascot style, soft rounded vector friendly linework, soft single key light from upper left, flat pastel cream background, centered full body composition, high consistency character design', now());
